class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number, optionally restricted to a specific country's format.

    This is intended to be a pragmatic check suitable for validating user input, not a fully comprehensive
    implementation of the international numbering plan.
    """

    _country_patterns = {
        'US': re.compile(r'^(?:\+1[\s.-]?)?\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4}$'),
        'GB': re.compile(r'^(?:\+44[\s.-]?|0)\d{2,4}[\s.-]?\d{3,4}[\s.-]?\d{3,4}$'),
    }
    _generic_international_pattern = re.compile(r'^\+\d{7,15}$')
    _generic_pattern = re.compile(r'^\+?[\d\s().-]+$')

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: An optional ISO 3166-1 alpha-2 country code (e.g. `'US'`, `'GB'`) used to restrict validation
                to that country's phone number format. If omitted, generic phone number validation is used.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber
        assert '020 7946 0958' == IsPhoneNumber
        assert 12345 != IsPhoneNumber

        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' != IsPhoneNumber('US')

        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')

        assert '+33 6 12 34 56 78' == IsPhoneNumber('FR')
        assert '6 12 34 56 78' != IsPhoneNumber('FR')
        ```
        """
        self.country = country.upper() if country else None
        super().__init__(plain_repr('*') if self.country is None else self.country)

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        if self.country is None:
            return self._is_generic_valid(other)

        pattern = self._country_patterns.get(self.country)
        if pattern is not None:
            return bool(pattern.match(other))
        else:
            return self._is_generic_international_valid(other)

    def _is_generic_valid(self, value: str) -> bool:
        if not self._generic_pattern.match(value):
            return False
        digits = re.sub(r'\D', '', value)
        return 7 <= len(digits) <= 15

    def _is_generic_international_valid(self, value: str) -> bool:
        stripped = re.sub(r'[\s.-]', '', value)
        return bool(self._generic_international_pattern.match(stripped))

